{
var size = context.TileSize;
var startX = GetFloat(parameters, "startX", 0.1f) * size;
var startY = GetFloat(parameters, "startY", 0.1f) * size;
var endX = GetFloat(parameters, "endX", 0.9f) * size;
var endY = GetFloat(parameters, "endY", 0.9f) * size;
var lineWidth = Math.Max(1, GetInt(parameters, "lineWidth", 1));
var lineColor = GetColor(parameters, "color", Colors.White);
var antiAlias = GetBool(parameters, "antiAlias", true);

var lR = lineColor.R / 255f;
var lG = lineColor.G / 255f;
var lB = lineColor.B / 255f;

// Clone input buffer or create empty one
PixelBuffer buffer;
if (inputs.Length > 0 && inputs[0] != null)
{
    buffer = inputs[0]!.Clone();
}
else
{
    buffer = PixelBufferPool.Borrow(size, size);
}

var halfWidth = lineWidth * 0.5f;

buffer.ParallelForEachPixel((x, y) =>
{
    // Compute shortest distance from pixel (x+0.5, y+0.5) to the line segment
    var px = x + 0.5f;
    var py = y + 0.5f;
    var dx = endX - startX;
    var dy = endY - startY;
    var lenSq = dx * dx + dy * dy;

    float dist;
    if (lenSq < 0.0001f)
    {
        // Degenerate: point-to-point distance
        dist = MathF.Sqrt((px - startX) * (px - startX) + (py - startY) * (py - startY));
    }
    else
    {
        var t = Math.Clamp(((px - startX) * dx + (py - startY) * dy) / lenSq, 0f, 1f);
        var nearX = startX + t * dx;
        var nearY = startY + t * dy;
        dist = MathF.Sqrt((px - nearX) * (px - nearX) + (py - nearY) * (py - nearY));
    }

    var alpha = antiAlias
        ? 1f - Math.Clamp((dist - (halfWidth - 0.5f)) / (halfWidth + 0.5f - (halfWidth - 0.5f) + 0.0001f), 0f, 1f)
        : (dist <= halfWidth ? 1f : 0f);

    if (alpha <= 0f) return;

    var (or, og, ob, oa) = buffer.GetPixel(x, y);
    // Blend with existing pixel (over operator)
    var outA = oa + alpha * (1f - oa);
    if (outA > 0f)
    {
        var outR = (or * oa + lR * alpha * (1f - oa)) / outA;
        var outG = (og * oa + lG * alpha * (1f - oa)) / outA;
        var outB = (ob * oa + lB * alpha * (1f - oa)) / outA;
        buffer.SetPixel(x, y, outR, outG, outB, outA);
    }
    else
    {
        buffer.SetPixel(x, y, lR, lG, lB, alpha);
    }
});

return buffer;
}
